// Basic input validation for updatable fields
function validateUpdates(updates) {
  const errors = [];

  if (updates.email !== undefined) {
    if (typeof updates.email !== 'string' || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(updates.email)) {
      errors.push({ field: 'email', message: 'Must be a valid email address' });
    }
  }

  if (updates.phone !== undefined) {
    if (typeof updates.phone !== 'string' || updates.phone.length < 7 || updates.phone.length > 20) {
      errors.push({ field: 'phone', message: 'Must be a valid phone number (7-20 characters)' });
    }
  }

  if (updates.bio !== undefined) {
    if (typeof updates.bio !== 'string' || updates.bio.length > 500) {
      errors.push({ field: 'bio', message: 'Bio must be a string with max 500 characters' });
    }
  }

  if (updates.role !== undefined) {
    const validRoles = ['admin', 'manager', 'user'];
    if (!validRoles.includes(updates.role)) {
      errors.push({ field: 'role', message: `Role must be one of: ${validRoles.join(', ')}` });
    }
  }

  if (updates.salary !== undefined) {
    if (typeof updates.salary !== 'number' || updates.salary < 0) {
      errors.push({ field: 'salary', message: 'Salary must be a non-negative number' });
    }
  }

  if (updates.internalNotes !== undefined) {
    if (typeof updates.internalNotes !== 'string' || updates.internalNotes.length > 1000) {
      errors.push({ field: 'internalNotes', message: 'Internal notes must be a string with max 1000 characters' });
    }
  }

  return errors;
}

